font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei', sans-serif;
background: var(--bg);
color: var(--text);
line-height: 1.7;
}
/* Hero */
.hero {
background: linear-gradient(135deg, #1e1b4b 0%, #312e81 40%, #4338ca 100%);
color: white;
padding: 80px 40px 60px;
text-align: center;
position: relative;
overflow: hidden;
}
.hero::before {
content: '';
position: absolute;
top: -50%;
left: -50%;
width: 200%;
height: 200%;
background: radial-gradient(circle at 30% 50%, rgba(99,102,241,0.15) 0%, transparent 60%),
radial-gradient(circle at 70% 50%, rgba(14,165,233,0.1) 0%, transparent 60%);
animation: shimmer 15s ease-in-out infinite;
}
@keyframes shimmer {
0%, 100% { transform: translate(0, 0) rotate(0deg); }
50% { transform: translate(-2%, -2%) rotate(2deg); }
}
.hero-content { position: relative; z-index: 1; }
.hero-badge {
display: inline-block;
background: rgba(255,255,255,0.12);
backdrop-filter: blur(10px);
border: 1px solid rgba(255,255,255,0.2);
padding: 6px 18px;
border-radius: 100px;
font-size: 13px;
letter-spacing: 1px;
margin-bottom: 24px;
}
.hero h1 {
font-size: 48px;
font-weight: 800;
letter-spacing: -1px;
margin-bottom: 12px;
background: linear-gradient(to right, #e0e7ff, #a5b4fc, #67e8f9);
-webkit-background-clip: text;
-webkit-text-fill-color: transparent;
}
.hero-sub {
font-size: 18px;
color: rgba(255,255,255,0.7);
max-width: 600px;
margin: 0 auto 20px;
}
.hero-meta {
display: flex;
justify-content: center;
gap: 32px;
flex-wrap: wrap;
}
.hero-meta span {
font-size: 14px;
color: rgba(255,255,255,0.6);
}
.hero-meta strong {
color: rgba(255,255,255,0.9);
font-weight: 600;
}
